-- Migration 017 — Descriptions du catalogue : objectifs officiels de la méthode THRIVE (par séance et tranche d'âge)
UPDATE public.video_sessions SET description = 'Objectif de la séance : Que le jeune se sente vu, valorisé et en sécurité. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 1 AND age_group = '8-11' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Apprendre au jeune à formuler un objectif simple qui dépend de lui (processus), pas du résultat. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 2 AND age_group = '8-11' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Faire vivre une progression de défi maîtrisée pour construire la confiance par l''expérience de réussite. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 3 AND age_group = '8-11' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Apprendre à reconnaître ce qui se passe intérieurement pendant l''action, surtout quand ça devient difficile. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 4 AND age_group = '8-11' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Apprendre au jeune à agir sur l''émotion identifiée en S4 avec une stratégie simple, choisie par lui, pour revenir au calme et au geste. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 5 AND age_group = '8-11' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Apprendre au jeune à faire redescendre son niveau de tension avant une action difficile, sans perdre son énergie ni sa concentration. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 6 AND age_group = '8-11' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Faire le point sur les progrès, redonner de l''autonomie au jeune, et préparer la deuxième moitié du programme. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 7 AND age_group = '8-11' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Apprendre au jeune à demander de l''aide de manière concrète, claire et sans honte, puis à reconnaître les personnes sur lesquelles il peut s''appuyer. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 8 AND age_group = '8-11' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Apprendre au jeune à ramener son attention avec son focus word quand il est distrait. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 9 AND age_group = '8-11' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Apprendre au jeune à se représenter mentalement un geste avant de le faire, de façon claire, sensorielle et utile pour la performance. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 10 AND age_group = '8-11' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Faire passer le jeune du statut d''apprenant accompagné à celui de praticien autonome de ses outils. Il nomme ses 6 outils, explique leur utilité, et remplit la Carte Ma Boîte à Outils qu''il garde après le programme. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 11 AND age_group = '8-11' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Faire passer le jeune du statut de bénéficiaire de l''apprentissage à celui de transmetteur capable d''influencer positivement les autres. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 12 AND age_group = '8-11' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Clôturer le programme en consolidant l''identité positive du jeune, validant ses progrès, et ancrant la projection vers l''après-programme. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 13 AND age_group = '8-11' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Créer une base d''alliance sécurisante, comprendre qui est le jeune, situer son vécu sportif, identifier ses premières forces, et formuler un rêve de saison qui servira de point d''ancrage pour tout le programme. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 1 AND age_group = '12-14' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Apprendre au jeune à formuler un objectif SMART orienté vers le processus et la maîtrise — d''abord dans le sport, puis dans sa vraie vie. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 2 AND age_group = '12-14' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Faire vivre au jeune une progression maîtrisée du défi pour construire des expériences de réussite, renforcer sa confiance, et nommer ses forces de courage et de persévérance. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 3 AND age_group = '12-14' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Apprendre au jeune à nommer précisément ce qu''il ressent pendant l''action, au moment où l''émotion monte. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 4 AND age_group = '12-14' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Apprendre au jeune à utiliser une stratégie de recentrage quand l''émotion monte pendant l''action — et retrouver son focus plus vite. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 5 AND age_group = '12-14' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Construire une routine stable de pré-performance — entrer dans un état de disponibilité mentale et corporelle avant d''agir, répétable sous pression réelle. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 6 AND age_group = '12-14' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Prendre du recul, mesurer ce qui a changé, réapproprier le programme — pas enseigner une nouvelle habileté. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 7 AND age_group = '12-14' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Normaliser la demande d''aide — apprendre à qui, quand, et comment demander de l''aide sans se sentir moins fort. Passer d''une logique de fermeture à une logique de ressource relationnelle. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 8 AND age_group = '12-14' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Apprendre à ramener son attention là où on veut qu''elle soit — au lieu de subir les distractions. La concentration n''est pas ne jamais partir, c''est revenir plus vite. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 9 AND age_group = '12-14' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Apprendre à se représenter mentalement le geste avant de l''exécuter — une simulation précise du mouvement, des sensations et du déroulé technique. Pas "penser positif" de façon vague. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 10 AND age_group = '12-14' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Consolider, nommer et s''approprier tout ce qui a été appris. Le jeune devient l''expert de son propre système — pas un participant qui répète le discours du coach. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 11 AND age_group = '12-14' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Faire passer le jeune du statut de bénéficiaire de l''apprentissage à celui de transmetteur capable d''influencer positivement les autres. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 12 AND age_group = '12-14' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Clôturer le programme en consolidant l''identité positive du jeune, validant ses progrès, et ancrant la projection vers l''après-programme. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 13 AND age_group = '12-14' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Créer une relation crédible avec un adolescent en phase d''investissement — comprendre son univers sportif et personnel, poser un cadre de travail clair et respectueux, récolter les premières données diagnostiques. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 1 AND age_group = '15-17' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Transformer le désir vague de progresser en plan clair, personnel et mesurable — co-construit par le jeune, signé par le jeune, appartenant au jeune. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 2 AND age_group = '15-17' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Faire vivre au jeune une expérience de maîtrise réelle dans un contexte contrôlé — pour qu''il commence à croire plus solidement en sa capacité à affronter le défi et réinterprète la difficulté comme une opportunité de progression. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 3 AND age_group = '15-17' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Apprendre au jeune à reconnaître ce qu''il ressent pendant un défi réel, au moment où l''émotion monte — passer de l''expérience brute à une identification simple, précise et exploitable. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 4 AND age_group = '15-17' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Apprendre au jeune à faire redescendre la charge émotionnelle pendant l''action pour rester fonctionnel — passer du constat à l''intervention avec deux outils concrets : respiration 4-7-8 et auto-talk personnel. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 5 AND age_group = '15-17' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Faire comprendre au jeune que demander de l''aide n''est pas un signe de faiblesse, mais une compétence de développement — déplacer la logique "je dois tout faire seul" vers "je peux m''appuyer stratégiquement sur des ressources autour de moi". À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 6 AND age_group = '15-17' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Faire un arrêt sur image pour mesurer les progrès, ajuster la trajectoire, et remettre le jeune aux commandes de son propre programme pour la deuxième moitié. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 7 AND age_group = '15-17' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Approfondir la compétence de demande d''aide — pas juste identifier des personnes-ressources, mais agir concrètement avant d''être au bout du rouleau, et distinguer l''aide qui renforce l''autonomie de l''aide qui l''empêche. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 8 AND age_group = '15-17' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Donner au jeune un outil simple pour revenir au geste quand des pensées parasites, la pression ou l''auto-critique apparaissent — pas une concentration parfaite, mais une capacité à revenir vite au bon focus. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 9 AND age_group = '15-17' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Enseigner au jeune comment se préparer mentalement avant d''exécuter un geste difficile — une répétition interne du mouvement qui active la préparation motrice sans effort physique complet. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 10 AND age_group = '15-17' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Faire passer le jeune de l''accumulation d''apprentissages à une vision intégrée de ses outils personnels — il nomme ses 6 outils THRIVE, les reformule avec ses mots, et explique dans quel contexte de vie il les utilise. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 11 AND age_group = '15-17' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Faire expérimenter au jeune qu''il peut influencer positivement quelqu''un d''autre — pas dominer ou performer, mais guider, démontrer et soutenir de manière utile. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 12 AND age_group = '15-17' AND lang = 'fr';
UPDATE public.video_sessions SET description = 'Objectif de la séance : Transformer la fin du programme en expérience de sens — pas un arrêt administratif. Le jeune voit noir sur blanc ce qu''il a appris, ce qu''il a gagné, et ce qu''il peut continuer à utiliser seul. À vivre ensemble, parent et enfant, pendant 20 minutes d''exercices interactifs guidés par le coach.' WHERE session_number = 13 AND age_group = '15-17' AND lang = 'fr';